+package org.openjdk.jmc.ui.ai;
+
+import java.util.ArrayList;
+import java.util.Collections;
+import java.util.List;
+import java.util.logging.Level;
+
+import org.eclipse.core.runtime.CoreException;
+import org.eclipse.core.runtime.IConfigurationElement;
+import org.eclipse.core.runtime.Platform;
+
+public class AIProviderRegistry {
+
+	private static final String EXTENSION_POINT_ID = "org.openjdk.jmc.ui.ai.aiProvider"; //$NON-NLS-1$
+	private static final String ELEMENT_PROVIDER = "provider"; //$NON-NLS-1$
+	private static final String ATTR_CLASS = "class"; //$NON-NLS-1$
+
+	private static AIProviderRegistry instance;
+	private List<IAIProvider> providers;
+
+	private AIProviderRegistry() {
+	}
+
+	public static synchronized AIProviderRegistry getInstance() {
+		if (instance == null) {
+			instance = new AIProviderRegistry();
+		}
+		return instance;
+	}
+
+	public List<IAIProvider> getProviders() {
+		if (providers == null) {
+			providers = loadProviders();
+		}
+		return Collections.unmodifiableList(providers);
+	}
+
+	public IAIProvider getProvider(String id) {
+		for (IAIProvider provider : getProviders()) {
+			if (provider.getId().equals(id)) {
+				return provider;
+			}
+		}
+		return null;
+	}
+
+	private List<IAIProvider> loadProviders() {
+		List<IAIProvider> result = new ArrayList<>();
+		IConfigurationElement[] elements = Platform.getExtensionRegistry()
+				.getConfigurationElementsFor(EXTENSION_POINT_ID);
+		for (IConfigurationElement element : elements) {
+			if (ELEMENT_PROVIDER.equals(element.getName())) {
+				try {
+					Object obj = element.createExecutableExtension(ATTR_CLASS);
+					if (obj instanceof IAIProvider) {
+						result.add((IAIProvider) obj);
+					}
+				} catch (CoreException e) {
+					AIPlugin.getLogger().log(Level.WARNING, "Failed to load AI provider: " + element.getAttribute("id"), //$NON-NLS-1$ //$NON-NLS-2$
+							e);
+				}
+			}
+		}
+		return result;
+	}
+}

