+		}
+
+		String eventType = JfrContext.extractString(TYPE_PATTERN, parametersJson);
+		if (eventType == null) {
+			return "Missing required parameter: eventType"; //$NON-NLS-1$
+		}
+
+		String function = JfrContext.extractString(FUNC_PATTERN, parametersJson);
+		if (function == null) {
