+		}
+		IMCThread thread = threadAccessor != null ? threadAccessor.getMember(item) : null;
+		if (thread != null) {
+			sb.append(" thread=").append(thread.getThreadName()); //$NON-NLS-1$
+		}
+		sb.append("\n"); //$NON-NLS-1$
+	}
+
+}

