+		int count = 0;
+		for (IItemIterable iterable : filtered) {
+			IType<IItem> type = iterable.getType();
+			for (IItem item : iterable) {
+				if (count >= limit) {
+					sb.append("... (truncated, ").append(limit).append(" of more events shown)\n"); //$NON-NLS-1$ //$NON-NLS-2$
+					return sb.toString();
